//! Bundled single-page chat UI for the Forge MVP.

pub const CHAT_HTML: &str = r#"<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Forge Unified</title>
  <style>
    :root{color-scheme:dark;--bg:#0b1020;--panel:#111a2e;--panel2:#18233a;--text:#edf4ff;--muted:#9fb0d0;--border:#2a3858;--accent:#67e8f9;--danger:#fb7185;--ok:#86efac}*{box-sizing:border-box}body{margin:0;min-height:100vh;background:radial-gradient(circle at top left,#1e3a5f 0,var(--bg) 42rem);color:var(--text);font:15px/1.45 system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}button,textarea{font:inherit}button{border:1px solid var(--border);background:var(--panel2);color:var(--text);border-radius:12px;padding:.65rem .9rem;cursor:pointer}button.primary{background:var(--accent);color:#04111f;border-color:transparent;font-weight:800}button:disabled{opacity:.55;cursor:not-allowed}.app{display:grid;grid-template-columns:minmax(240px,320px) minmax(0,1fr);min-height:100vh}aside{border-right:1px solid var(--border);background:rgba(17,26,46,.88);padding:1rem;display:flex;flex-direction:column;gap:1rem}main{min-width:0;display:grid;grid-template-rows:auto 1fr auto;min-height:100vh}.brand{display:flex;justify-content:space-between;gap:1rem;align-items:start}h1{font-size:1.2rem;margin:0}.subtitle{color:var(--muted);font-size:.86rem;margin-top:.25rem}.pill{display:inline-flex;align-items:center;padding:.25rem .55rem;border:1px solid var(--border);border-radius:999px;color:var(--muted);font-size:.78rem;white-space:nowrap}.status-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:.55rem}.metric{background:rgba(24,35,58,.82);border:1px solid var(--border);border-radius:14px;padding:.75rem}.metric strong{display:block;font-size:1.2rem}.metric span{color:var(--muted);font-size:.78rem}.conv-list{display:flex;flex-direction:column;gap:.45rem;overflow:auto}.conv{text-align:left;width:100%;border-radius:14px;padding:.75rem}.conv.active{border-color:var(--accent);box-shadow:0 0 0 1px rgba(103,232,249,.25) inset}.conv-title{font-weight:800;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}.conv-meta{color:var(--muted);font-size:.78rem;margin-top:.2rem}.topbar{border-bottom:1px solid var(--border);padding:1rem clamp(1rem,3vw,1.5rem);display:flex;justify-content:space-between;gap:1rem;align-items:center;background:rgba(11,16,32,.66)}.chat-title{font-size:1rem;font-weight:800}.actions{display:flex;flex-wrap:wrap;gap:.5rem;justify-content:end}.messages{padding:1rem clamp(1rem,3vw,1.5rem);overflow:auto;display:flex;flex-direction:column;gap:.8rem}.empty{margin:auto;max-width:760px;border:1px solid var(--border);background:rgba(17,26,46,.82);border-radius:24px;padding:1.5rem}.empty h2{margin-top:0}.message{max-width:920px;border:1px solid var(--border);border-radius:18px;padding:.9rem;background:rgba(17,26,46,.82);white-space:pre-wrap;overflow-wrap:anywhere}.message.user{align-self:flex-end;background:rgba(103,232,249,.13);border-color:rgba(103,232,249,.42)}.message.assistant{align-self:flex-start}.message.tool{align-self:stretch;max-width:none;background:rgba(24,35,58,.72)}.role{display:flex;justify-content:space-between;color:var(--muted);font-size:.78rem;margin-bottom:.45rem;text-transform:uppercase;letter-spacing:.04em}details.tool-block{border:1px solid var(--border);border-radius:14px;padding:.65rem;margin-top:.5rem;background:rgba(0,0,0,.16)}details.tool-block summary{cursor:pointer;color:var(--accent);font-weight:800}pre{margin:.65rem 0 0;padding:.8rem;border-radius:12px;background:#050914;overflow:auto;max-height:24rem;color:#d9e7ff}.composer{border-top:1px solid var(--border);padding:1rem clamp(1rem,3vw,1.5rem);background:rgba(11,16,32,.88)}.composer-inner{display:grid;grid-template-columns:1fr auto;gap:.75rem;align-items:end}textarea{width:100%;min-height:4.5rem;max-height:12rem;resize:vertical;border-radius:16px;border:1px solid var(--border);color:var(--text);background:rgba(17,26,46,.92);padding:.85rem}.hint{color:var(--muted);font-size:.8rem;margin-top:.45rem}.toast{position:fixed;right:1rem;bottom:1rem;max-width:min(36rem,calc(100vw - 2rem));background:#09111f;border:1px solid var(--border);border-radius:16px;padding:.8rem .9rem;color:var(--text);box-shadow:0 18px 60px rgba(0,0,0,.35);display:none;z-index:20}.toast.show{display:block}.error{color:var(--danger)}.ok{color:var(--ok)}@media(max-width:780px){.app{grid-template-columns:1fr}aside{border-right:0;border-bottom:1px solid var(--border);max-height:38vh}main{min-height:62vh}.composer-inner{grid-template-columns:1fr}.actions{justify-content:start}}
  </style>
</head>
<body>
  <div class="app">
    <aside>
      <div class="brand"><div><h1>Forge Unified</h1><div class="subtitle">MVP chat wired to the Rust engine.</div></div><span class="pill" id="health-pill">checking</span></div>
      <button id="new-conversation" class="primary" type="button">New conversation</button>
      <div class="status-grid" aria-live="polite"><div class="metric"><strong id="conversation-count">0</strong><span>conversations</span></div><div class="metric"><strong id="message-count">0</strong><span>messages</span></div></div>
      <div class="conv-list" id="conversation-list" aria-label="Conversations"></div>
    </aside>
    <main>
      <div class="topbar"><div><div class="chat-title" id="chat-title">No conversation selected</div><div class="subtitle" id="chat-subtitle">Create a conversation, then ask Forge to inspect or change the repo.</div></div><div class="actions"><button id="refresh" type="button">Refresh</button><button id="snapshot" type="button" disabled>Save snapshot</button><button id="graph" type="button">Graph</button></div></div>
      <section class="messages" id="messages" aria-live="polite"></section>
      <div class="composer"><div class="composer-inner"><label><span class="subtitle">Message</span><textarea id="message-input" placeholder="Example: Inspect this repo and tell me the next smallest code change to make the app usable." disabled></textarea></label><button id="send" class="primary" type="button" disabled>Send</button></div><div class="hint">Enter sends. Shift+Enter inserts a newline. Tool calls and results appear after the run finishes.</div></div>
    </main>
  </div>
  <div class="toast" id="toast" role="status" aria-live="polite"></div>
  <script>
    const state={conversations:[],activeId:null,activeConversation:null,busy:false};
    const $=(id)=>document.getElementById(id);
    function toast(message,kind=''){const el=$('toast');el.textContent=message;el.className='toast show '+kind;clearTimeout(toast.timer);toast.timer=setTimeout(()=>{el.className='toast'},4500)}
    async function api(path,options={}){const response=await fetch(path,{headers:{'content-type':'application/json',...(options.headers||{})},...options});const text=await response.text();let data=null;try{data=text?JSON.parse(text):null}catch{data=text}if(!response.ok){const detail=typeof data==='string'?data:JSON.stringify(data);throw new Error(`${response.status} ${response.statusText}: ${detail}`)}return data}
    async function checkHealth(){try{const health=await api('/api/health');$('health-pill').textContent=health.status||'ok';$('health-pill').classList.add('ok')}catch{$('health-pill').textContent='offline';$('health-pill').classList.add('error')}}
    async function loadConversations(selectFirst=false){state.conversations=await api('/api/conversations');$('conversation-count').textContent=String(state.conversations.length);renderConversationList();if(!state.activeId&&selectFirst&&state.conversations.length){await selectConversation(state.conversations[0].id)}}
    function renderConversationList(){const list=$('conversation-list');list.innerHTML='';for(const conv of state.conversations){const button=document.createElement('button');button.type='button';button.className='conv'+(conv.id===state.activeId?' active':'');button.innerHTML='<div class="conv-title"></div><div class="conv-meta"></div>';button.querySelector('.conv-title').textContent=conv.title||'Untitled';button.querySelector('.conv-meta').textContent=`${conv.message_count} messages · ${conv.mode}`;button.addEventListener('click',()=>selectConversation(conv.id));list.appendChild(button)}}
    async function createConversation(){const title=`Forge run ${new Date().toLocaleString()}`;const created=await api('/api/conversations',{method:'POST',body:JSON.stringify({title})});state.activeId=created.id;await loadConversations(false);await selectConversation(created.id);toast('Conversation created','ok')}
    async function selectConversation(id){state.activeId=id;state.activeConversation=await api(`/api/conversations/${encodeURIComponent(id)}`);$('chat-title').textContent=state.activeConversation.title||'Untitled';$('chat-subtitle').textContent=id;$('message-input').disabled=false;$('send').disabled=state.busy;$('snapshot').disabled=false;$('message-count').textContent=String((state.activeConversation.messages||[]).length);renderConversationList();renderMessages()}
    function renderMessages(){const container=$('messages');container.innerHTML='';const messages=state.activeConversation?.messages||[];if(!messages.length){container.innerHTML='<div class="empty"><h2>Ready to build</h2><p>Ask Forge to inspect files, explain the repo, or make a small code change. This UI calls the real Rust chat endpoint and reloads the conversation so tool calls/results are visible.</p></div>';return}for(const msg of messages){const article=document.createElement('article');const role=(msg.role||'unknown').toLowerCase();article.className=`message ${role}`;const header=document.createElement('div');header.className='role';header.innerHTML='<span></span><span></span>';header.children[0].textContent=role;const toolCount=(msg.tool_calls?.length||msg.tool_results?.length||0);header.children[1].textContent=toolCount?`${toolCount} tool item(s)`:'';article.appendChild(header);if(msg.content){const body=document.createElement('div');body.textContent=msg.content;article.appendChild(body)}if(msg.tool_calls){for(const call of msg.tool_calls){article.appendChild(toolDetails('Tool call',call.kind||'unknown',call.args||call))}}if(msg.tool_results){for(const result of msg.tool_results){article.appendChild(toolDetails(result.success?'Tool result':'Tool error',result.kind||'unknown',result))}}container.appendChild(article)}container.scrollTop=container.scrollHeight}
    function toolDetails(label,name,payload){const details=document.createElement('details');details.className='tool-block';const summary=document.createElement('summary');summary.textContent=`${label}: ${name}`;const pre=document.createElement('pre');pre.textContent=JSON.stringify(payload,null,2);details.appendChild(summary);details.appendChild(pre);return details}
    async function sendMessage(){const input=$('message-input');const message=input.value.trim();if(!state.activeId||!message||state.busy)return;state.busy=true;input.value='';$('send').disabled=true;$('message-input').disabled=true;toast('Running Forge task...');try{await api(`/api/conversations/${encodeURIComponent(state.activeId)}/chat`,{method:'POST',body:JSON.stringify({message,max_rounds:10})});await selectConversation(state.activeId);await loadConversations(false);toast('Run finished','ok')}catch(err){toast(err.message,'error')}finally{state.busy=false;$('message-input').disabled=!state.activeId;$('send').disabled=!state.activeId}}
    async function saveSnapshot(){if(!state.activeId)return;await api(`/api/conversations/${encodeURIComponent(state.activeId)}/snapshot`,{method:'POST',body:'{}'});toast('Snapshot saved','ok')}
    $('new-conversation').addEventListener('click',()=>createConversation().catch(err=>toast(err.message,'error')));$('refresh').addEventListener('click',()=>Promise.all([loadConversations(false),state.activeId?selectConversation(state.activeId):null]).catch(err=>toast(err.message,'error')));$('snapshot').addEventListener('click',()=>saveSnapshot().catch(err=>toast(err.message,'error')));$('graph').addEventListener('click',()=>{window.location.href='/api/graph'});$('send').addEventListener('click',()=>sendMessage());$('message-input').addEventListener('keydown',(event)=>{if(event.key==='Enter'&&!event.shiftKey){event.preventDefault();sendMessage()}});
    checkHealth();loadConversations(true).catch(err=>toast(err.message,'error'));
  </script>
</body>
</html>"#;
